// ── Topic Navigation Bar ─────────────────────────────────────
// Uses slug-based index so matching is exact — no name mismatch bugs.
function TopicNav({ currentIndex, onNavigate }) {
  const isFirst = currentIndex === 0;
  const isLast  = currentIndex === TOPIC_SLUGS.length - 1;

  // Shared active button style
  const activeBtn = {
    display:      "inline-flex",
    alignItems:   "center",
    gap:          "6px",
    padding:      "10px 20px",
    borderRadius: "10px",
    border:       "none",
    fontSize:     "0.82rem",
    fontWeight:   500,
    fontFamily:   "Poppins, sans-serif",
    cursor:       "pointer",
    background:   "linear-gradient(135deg, #6366f1, #4f46e5)",
    color:        "#fff",
    boxShadow:    "0 0 16px rgba(99,102,241,0.35)",
    transition:   "transform 0.15s ease, box-shadow 0.2s ease",
  };

  // Disabled style for Previous on first topic
  const disabledBtn = {
    display:      "inline-flex",
    alignItems:   "center",
    gap:          "6px",
    padding:      "10px 20px",
    borderRadius: "10px",
    fontSize:     "0.82rem",
    fontWeight:   500,
    fontFamily:   "Poppins, sans-serif",
    cursor:       "not-allowed",
    background:   "rgba(255,255,255,0.03)",
    color:        "#2d3748",
    border:       "1px solid rgba(255,255,255,0.06)",
  };

  return (
    <div
      className="mt-10 pt-6"
      style={{ borderTop: "1px solid rgba(255,255,255,0.07)" }}
    >
      <div className="flex items-center justify-between gap-3 flex-wrap">

        {/* ── Previous Topic ── */}
        <button
          disabled={isFirst}
          onClick={() => !isFirst && onNavigate(currentIndex - 1)}
          style={isFirst ? disabledBtn : activeBtn}
          onMouseEnter={(e) => { if (!isFirst) e.currentTarget.style.transform = "translateY(-2px)"; }}
          onMouseLeave={(e) => { e.currentTarget.style.transform = "none"; }}
        >
          ← Previous Topic
        </button>

        {/* ── Position counter ── */}
        <span style={{ fontSize: "0.75rem", fontFamily: "JetBrains Mono, monospace", color: "#334155" }}>
          {currentIndex + 1} / {TOPIC_SLUGS.length}
        </span>

        {/* ── Next Topic or Completion ── */}
        {isLast ? (
          <span
            style={{
              fontSize:     "0.75rem",
              fontFamily:   "JetBrains Mono, monospace",
              padding:      "8px 14px",
              borderRadius: "10px",
              background:   "rgba(34,197,94,0.08)",
              color:        "#86efac",
              border:       "1px solid rgba(34,197,94,0.18)",
            }}
          >
            ✓ You've completed all topics
          </span>
        ) : (
          <button
            onClick={() => onNavigate(currentIndex + 1)}
            style={activeBtn}
            onMouseEnter={(e) => { e.currentTarget.style.transform = "translateY(-2px)"; }}
            onMouseLeave={(e) => { e.currentTarget.style.transform = "none"; }}
          >
            Next Topic →
          </button>
        )}
      </div>
    </div>
  );
}

// ── Main LearnPage ───────────────────────────────────────────
export default function LearnPage() {
  const { topicName } = useParams();           // slug from URL e.g. "profit-and-loss"
  const navigate      = useNavigate();
  const localTopic    = getTopicBySlug(topicName);
  const displayName   = localTopic?.name || topicName?.replace(/-/g, " ");

  // ✅ Match by slug — 100% reliable, no display-name mismatch
  const currentIndex = TOPIC_SLUGS.indexOf(topicName);

  const { fetchLearnContent, loading, error } = useLearn();
  const [content,  setContent]  = useState(null);
  const [retryKey, setRetryKey] = useState(0);

  useEffect(() => {
    if (!displayName) return;
    setContent(null);
    window.scrollTo({ top: 0, behavior: "smooth" });
    fetchLearnContent(displayName).then((data) => {
      if (data) setContent(data);
    });
  }, [displayName, retryKey]); // eslint-disable-line

  const handleRetry = () => setRetryKey((k) => k + 1);

  // Navigate to topic by index using its slug directly
  const handleNavigate = (index) => {
    navigate(`/topic/${TOPIC_SLUGS[index]}`);
  };

  return (
    <main className="max-w-3xl mx-auto px-5 py-10">

      {/* Breadcrumb */}
      <div className="flex items-center gap-2 text-xs text-slate-500 mb-8 animate-fade-in">
        <Link to="/" className="hover:text-slate-300 transition-colors no-underline">Home</Link>
        <span>/</span>
        <span className="text-slate-300">{displayName}</span>
      </div>

      {/* Title */}
      <div className="mb-8 animate-fade-up">
        <h1 className="text-2xl font-bold text-white mb-1" style={{ letterSpacing: "-0.01em" }}>
          {displayName}
        </h1>
        {localTopic && (
          <span className="section-label" style={{ color: "#6366f1" }}>
            {localTopic.category}
          </span>
        )}
      </div>

      {/* States */}
      {loading && <Skeleton />}
      {!loading && error && <ErrorPanel message={error} onRetry={handleRetry} />}
      {!loading && !error && content && (
        <>
          <ConceptSection   concept={content.concept} />
          <FormulasSection  formulas={content.formulas} />
          <ShortcutsSection shortcuts={content.shortcuts} />
          <ExamplesSection  examples={content.examples} />
          <PracticeSection  practice={content.practice} />
          <SummarySection   summary={content.summary} />
        </>
      )}

      {/* ✅ Navigation — always shown when slug is in TOPIC_SLUGS */}
      {currentIndex !== -1 && (
        <TopicNav currentIndex={currentIndex} onNavigate={handleNavigate} />
      )}

      {/* Back link */}
      <div className="mt-6">
        <Link to="/" className="text-xs text-slate-500 hover:text-slate-300 transition-colors no-underline">
          ← Back to all topics
        </Link>
      </div>

      <div className="h-16" />
    </main>
  );
}
